function a(t){if(t===null||t<=0)return"-";const o=Math.ceil(t/1e3);if(o<60)return`${o}s`;const r=Math.floor(o/60),n=o%60;return n===0?`${r}m`:`${r}m${n}s`}function i(t){if(!t)return"-";const o=new Date(t).getTime();if(Number.isNaN(o))return"-";const r=Math.max(0,Math.floor((Date.now()-o)/1e3));if(r<60)return`${r}s ago`;const n=Math.floor(r/60);if(n<60)return`${n}min ago`;const e=Math.floor(n/60);return e<24?`${e}h ago`:`${Math.floor(e/24)}d ago`}function u(t){return t?new Date(t).toLocaleTimeString("zh-CN",{hour12:!1}):"--:--:--"}function c(t){return new Date(t).toLocaleString("zh-CN",{hour12:!1})}export{a,c as b,i as c,u as f};
